// Created: 2026-03-18

/**
 * StopFailure Handler (CC 2.1.78)
 * Issue #1106: Graceful session death handling
 *
 * Fires when a turn ends due to an API error (rate limit, auth failure, etc.).
 * Flushes session state and writes an emergency handoff so the next session
 * can resume cleanly.
 *
 * ERROR-LOOP SAFETY: This handler MUST return outputSilentSuccess() — never
 * produce additionalContext or systemMessage. CC 2.1.78 fixed an infinite loop
 * where stop hooks re-fed errors to the model. StopFailure is especially
 * dangerous because it fires ON errors — any output here could re-trigger.
 */

import { existsSync, mkdirSync } from 'node:fs';
import { execFileSync } from 'node:child_process';
import type { HookInput, HookResult } from '../types.js';
import {
  outputSilentSuccess,
  logHook,
  getProjectDir,
  getSessionId,
  getCachedBranch,
} from '../lib/common.js';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { flushEventCounter, trackEvent } from '../lib/session-tracker.js';
import { flush as flushAnalyticsBuffer } from '../lib/analytics-buffer.js';

const HOOK_NAME = 'stop-failure-handler';

/**
 * Handle StopFailure event — flush state and write emergency handoff.
 *
 * This is a last-resort handler. The session is dying from an API error.
 * We must:
 * 1. Flush buffered analytics/events to disk
 * 2. Write a minimal handoff file for session recovery
 * 3. Return silent success (NEVER produce output)
 */
export async function stopFailureHandler(input: HookInput): Promise<HookResult> {
  // Re-entry guard (same as Stop dispatcher)
  if (input.stop_hook_active) {
    logHook(HOOK_NAME, 'Skipping: stop_hook_active=true (re-entry prevention)');
    return outputSilentSuccess();
  }

  const failureReason = input.stop_failure_reason || 'unknown';
  const apiStatus = input.api_status_code;

  logHook(HOOK_NAME, `StopFailure: reason=${failureReason} status=${apiStatus ?? 'N/A'}`, 'warn');

  // Track the failure event for analytics
  try {
    trackEvent('session_end', 'stop-failure', {
      success: false,
      context: `API failure: ${failureReason}${apiStatus ? ` (HTTP ${apiStatus})` : ''}`,
    });
  } catch {
    // Never fail on tracking
  }

  // Flush all buffered state to disk
  try {
    flushEventCounter();
  } catch {
    logHook(HOOK_NAME, 'Failed to flush event counter', 'warn');
  }

  try {
    flushAnalyticsBuffer();
  } catch {
    logHook(HOOK_NAME, 'Failed to flush analytics buffer', 'warn');
  }

  // Write emergency handoff
  try {
    const projectDir = input.project_dir || getProjectDir();
    const sessionId = input.session_id || getSessionId();
    const branch = getCachedBranch(projectDir);
    const handoffDir = `${projectDir}/.claude`;
    const handoffPath = `${handoffDir}/HANDOFF.md`;

    if (!existsSync(handoffDir)) {
      mkdirSync(handoffDir, { recursive: true });
    }

    // Get modified files (best-effort, may fail if git is unavailable)
    let modifiedFiles: string[] = [];
    try {
      const status = execFileSync('git', ['status', '--porcelain'], {
        cwd: projectDir,
        encoding: 'utf8',
        timeout: 3000,
        stdio: ['pipe', 'pipe', 'pipe'],
      }).trim();
      if (status) {
        modifiedFiles = status.split('\n').map(l => l.trim());
      }
    } catch {
      // Git unavailable — skip
    }

    const timestamp = new Date().toISOString().replace('T', ' ').slice(0, 19);
    const sections = [
      '# Session Handoff (Emergency — API Failure)',
      '',
      `**Branch**: ${branch}`,
      `**When**: ${timestamp} UTC`,
      `**Session**: ${sessionId}`,
      `**Failure**: ${failureReason}${apiStatus ? ` (HTTP ${apiStatus})` : ''}`,
      '',
      '## Summary',
      `Session terminated by API error: ${failureReason}. Work may be incomplete.`,
      'Review git status and recent changes before continuing.',
    ];

    if (modifiedFiles.length > 0) {
      sections.push('', '## Modified Files');
      for (const file of modifiedFiles.slice(0, 30)) {
        sections.push(`- ${file}`);
      }
      if (modifiedFiles.length > 30) {
        sections.push(`- ... and ${modifiedFiles.length - 30} more`);
      }
    }

    // Get last assistant message snippet if available
    if (input.last_assistant_message) {
      const snippet = input.last_assistant_message.substring(0, 500);
      sections.push('', '## Last Assistant Message (truncated)', snippet);
    }

    atomicWriteSync(handoffPath, `${sections.join('\n')}\n`);
    logHook(HOOK_NAME, `Wrote emergency handoff: ${handoffPath}`);
  } catch (error) {
    const msg = error instanceof Error ? error.message : String(error);
    logHook(HOOK_NAME, `Failed to write emergency handoff: ${msg}`, 'warn');
  }

  // CRITICAL: Always return silent success — never produce output
  return outputSilentSuccess();
}
